52	void RTLILBuilder::bless_cell(RTLIL::Cell *cell)
53	{
54		cell->attributes = staged_attributes;
55		if (staged_source_range_valid && !cell->attributes.count(ID::src)) {
56			auto src = format_src(staged_source_range);
57			if (!src.empty())
58				cell->attributes[ID::src] = src;
59		}
60	}
