123	SigSpec RTLILBuilder::EqWildcard(SigSpec a, SigSpec b)
124	{
125		log_assert(a.size() == b.size());
126		log_assert(b.is_fully_const());
127	
128		for (int i = a.size() - 1; i >= 0; i--) {
129			if (b[i] == RTLIL::Sx || b[i] == RTLIL::Sz) {
130				a.remove(i);
131				b.remove(i);
132			}
133		}
134		log_assert(a.size() == b.size());
135		if (a.is_fully_const() && b.is_fully_const())
136			return RTLIL::const_eq(a.as_const(), b.as_const(), false, false, 1);
137		auto [id, y] = add_y_wire(1);
138		bless_cell(canvas->addEq(id, a, b, y, false));
139		return y;
140	}
