142	SigSpec RTLILBuilder::LogicAnd(SigSpec a, SigSpec b)
143	{
144		if (a.is_fully_zero() || b.is_fully_zero())
145			return RTLIL::Const(0, 1);
146		if (a.is_fully_def() && b.size() == 1)
147			return b;
148		if (b.is_fully_def() && a.size() == 1)
149			return a;
150		auto [id, y] = add_y_wire(1);
151		bless_cell(canvas->addLogicAnd(id, a, b, y));
152		return y;
153	}
