175	SigSpec RTLILBuilder::Mux(SigSpec a, SigSpec b, SigSpec s)
176	{
177		log_assert(a.size() == b.size());
178		log_assert(s.size() == 1);
179		if (s[0] == RTLIL::S0)
180			return a;
181		if (s[0] == RTLIL::S1)
182			return b;
183		auto [id, y] = add_y_wire(a.size());
184		bless_cell(canvas->addMux(id, a, b, s, y));
185		return y;
186	}
