188	SigSpec RTLILBuilder::Bwmux(SigSpec a, SigSpec b, SigSpec s)
189	{
190		log_assert(a.size() == b.size());
191		log_assert(a.size() == s.size());
192		if (s.is_fully_const()) {
193			SigSpec result(RTLIL::Sx, a.size());
194			for (int i = 0; i < a.size(); i++) {
195				if (s[i] == RTLIL::S0)
196					result[i] = a[i];
197				else if (s[i] == RTLIL::S1)
198					result[i] = b[i];
199			}
200			return result;
201		}
202		auto [id, y] = add_y_wire(a.size());
203		bless_cell(canvas->addBwmux(id, a, b, s, y));
204		return y;
205	}
