260	SigSpec RTLILBuilder::Bmux(SigSpec a, SigSpec s)
261	{
262		log_assert(a.size() % (1 << s.size()) == 0);
263		log_assert(a.size() >= 1 << s.size());
264		int stride = a.size() >> s.size();
265		if (s.is_fully_def()) {
266			return a.extract(s.as_const().as_int() * stride, stride);
267		}
268		auto [id, y] = add_y_wire(stride);
269		bless_cell(canvas->addBmux(id, a, s, y));
270		return y;
271	}
