333	SigSpec RTLILBuilder::Biop(
334			IdString op, SigSpec a, SigSpec b, bool a_signed, bool b_signed, int y_width)
335	{
336		if (a.is_fully_const() && b.is_fully_const()) {
337	#define OP(type)                                                                                   \
338		if (op == ID($##type))                                                                         \
339			return RTLIL::const_##type(a.as_const(), b.as_const(), a_signed, b_signed, y_width);
340			OP(add)
341			OP(sub)
342			OP(mul)
343			OP(divfloor)
344			OP(div)
345			OP(mod)
346			OP(and)
347			OP(or)
348			OP(xor)
349			OP(xnor)
350			OP(eq)
351			OP(ne)
352			OP(nex)
353			OP(eqx)
354			OP(ge)
355			OP(gt)
356			OP(le)
357			OP(lt)
358			OP(logic_and)
359			OP(logic_or)
360			OP(sshl)
361			OP(sshr)
362			OP(shl)
363			OP(shr)
364			OP(pow)
365	#undef OP
366		}
367	
368		if (op.in(ID($le), ID($lt), ID($gt), ID($ge)) && !a.empty() && !b.empty()) {
369			int carry = op.in(ID($le), ID($ge)) ? -1 : 1;
370			int al = 0, bl = 0;
371			// Defer to three-valued evaluation over a representation of the operators.
372			// This is a bit much, but I'm writing this tired and don't trust doing it
373			// another way.
374			int width = std::max(a.size(), b.size());
375			for (int i = 0; i < width; i++) {
376				RTLIL::SigBit abit = i < a.size() ? a[i] : (a_signed ? a.msb() : RTLIL::S0);
377				RTLIL::SigBit bbit = i < b.size() ? b[i] : (b_signed ? b.msb() : RTLIL::S0);
378				al = ThreeValued::convert(abit);
379				bl = ThreeValued::convert(bbit);
380				if (op.in(ID($gt), ID($ge)))
381					std::swap(al, bl);
382				if (i != width - 1)
383					carry = ThreeValued::CARRY(al, ThreeValued::NOT(bl), carry);
384			}
385			int result = ThreeValued::XOR(carry, ThreeValued::XNOR(al, bl));
386			if (result < 0)
387				return SigSpec(RTLIL::S0, y_width);
388			if (result > 0) {
389				SigSpec ret = {RTLIL::S1};
390				ret.extend_u0(y_width);
391				return ret;
392			}
393		}
394	
395		if (op == ID($logic_and)) {
396			if (a.is_fully_zero() || b.is_fully_zero())
397				return SigSpec(RTLIL::S0, y_width);
398		}
399	
400		if (op == ID($logic_or)) {
401			// IMPROVEMENT: condition could be relaxed
402			if ((a.is_fully_const() && a.as_bool()) || (b.is_fully_const() && b.as_bool())) {
403				SigSpec ret = {RTLIL::S1};
404				ret.extend_u0(y_width);
405				return ret;
406			}
407		}
408	
409		int msb_zeroes = 0;
410		if (op == ID($mul) && !a_signed && !b_signed) {
411			int as = a.size(), bs = b.size();
412			while (as > 0 && a[as - 1] == RTLIL::S0)
413				as--;
414			while (bs > 0 && b[bs - 1] == RTLIL::S0)
415				bs--;
416			msb_zeroes = std::max(0, y_width - (as + bs));
417		}
418	
419		auto [id, y] = add_y_wire(y_width - msb_zeroes);
420		Cell *cell = canvas->addCell(id, op);
421		cell->setPort(RTLIL::ID::A, a);
422		cell->setPort(RTLIL::ID::B, b);
423		cell->setParam(RTLIL::ID::A_WIDTH, a.size());
424		cell->setParam(RTLIL::ID::B_WIDTH, b.size());
425		cell->setParam(RTLIL::ID::A_SIGNED, a_signed);
426		cell->setParam(RTLIL::ID::B_SIGNED, b_signed);
427		cell->setParam(RTLIL::ID::Y_WIDTH, y_width - msb_zeroes);
428		cell->setPort(RTLIL::ID::Y, y);
429		bless_cell(cell);
430		return {SigSpec(RTLIL::S0, msb_zeroes), y};
431	}
