545	void RTLILBuilder::add_aldffe(std::string_view name, const RTLIL::SigSpec &clk,
546			const RTLIL::SigSpec &en, const RTLIL::SigSpec &aload, const RTLIL::SigSpec &d,
547			const RTLIL::SigSpec &q, const RTLIL::SigSpec &ad, bool clk_polarity, bool en_polarity,
548			bool aload_polarity)
549	{
550		if (en.is_fully_def() && en.as_bool() == en_polarity) {
551			return add_aldff(name, clk, aload, d, q, ad, clk_polarity, aload_polarity);
552		}
553	
554		RTLIL::Cell *cell = canvas->addAldffe(canvas->uniquify(id(name)), clk, en, aload, d, q, ad,
555				clk_polarity, en_polarity, aload_polarity);
556		bless_cell(cell);
557	}
558	
559	SigSpec RTLILBuilder::CountOnes(SigSpec sig, int result_width)
560	{
561		SigSpec ret;
562		auto width = sig.size();
563		if (width == 0) {
564			ret = RTLIL::Const(0, 1);
565		} else if (width == 1) {
566			// Single bit
567			ret = sig;
568		} else {
569			// Build tree of adders
570			std::vector<RTLIL::SigSpec> curr_level;
571			for (int i = 0; i < width; i++) {
572				RTLIL::SigSpec bit = sig[i];
573				bit.extend_u0(result_width);
574				curr_level.push_back(bit);
575			}
576	
577			while (curr_level.size() > 1) {
578				std::vector<RTLIL::SigSpec> nxt_level;
579				for (size_t i = 0; i + 1 < curr_level.size(); i += 2) {
580					auto sum = Biop(
581							ID($add), curr_level[i], curr_level[i + 1], false, false, result_width);
582					if (sum.size() < result_width)
583						sum.extend_u0(result_width);
584					nxt_level.push_back(sum);
585				}
586				if (curr_level.size() % 2 == 1) {
587					nxt_level.push_back(curr_level.back());
588				}
589				curr_level = std::move(nxt_level);
590			}
591			ret = curr_level[0];
592		}
593		// Extend to expected type width
594		ret.extend_u0(result_width);
595		return ret;
596	}
597	
598	SigSpec RTLILBuilder::Clog2(SigSpec sig, int result_width)
599	{
600		int width = sig.size();
601	
602		if (width == 0)
603			return RTLIL::Const(0, result_width);
604	
605		SigSpec n_minus_1 = Biop(ID($sub), sig, RTLIL::Const(1, width), false, false, width);
606	
607		SigSpec result = RTLIL::Const(0, result_width);
608		for (int i = 0; i < width; i++)
609			result = Mux(result, RTLIL::Const(i + 1, result_width), n_minus_1[i]);
610	
611		SigSpec n_not_zero = ReduceBool(sig);
612		return Mux(RTLIL::Const(0, result_width), result, n_not_zero);
613	}
614	
615	static const RTLIL::Const reverse_data(RTLIL::Const &orig, int width)
616	{
617		std::vector<RTLIL::State> bits;
618		log_assert(orig.size() % width == 0);
619		bits.reserve(orig.size());
620		for (int i = orig.size() - width; i >= 0; i -= width)
621			bits.insert(bits.end(), orig.begin() + i, orig.begin() + i + width);
622		return bits;
623	}
624	
625	// Private helper
626	void RTLILBuilder::emit_meminit_cell(RTLIL::Memory *mem, uint64_t word_offset, bool big_endian,
627			RTLIL::Const data, RTLIL::Const mask)
628	{
629		if (data.empty())
630			return;
631	
632		int abits = 32; // TODO: error out if abits too low
633		int nwords = data.size() / mem->width;
634		log_assert(data.size() % mem->width == 0);
635		log_assert(mask.size() == mem->width);
636		RTLIL::Cell *cell = canvas->addCell(new_id(), ID($meminit_v2));
637		cell->setParam(ID::MEMID, mem->name.str());
638		cell->setParam(ID::PRIORITY, meminit_prio_counter++);
639		cell->setParam(ID::ABITS, abits);
640		cell->setParam(ID::WORDS, nwords);
641		cell->setParam(ID::WIDTH, mem->width);
642		cell->setPort(ID::ADDR,
643				mem->start_offset + (big_endian ? (mem->size - word_offset - nwords) : word_offset));
644		cell->setPort(ID::DATA, big_endian ? reverse_data(data, mem->width) : data);
645		cell->setPort(ID::EN, mask);
646		bless_cell(cell);
647	}
648	
649	void RTLILBuilder::add_memory_init(
650			std::string_view name, uint64_t bit_offset, bool big_endian, RTLIL::Const data)
651	{
652		if (data.empty())
653			return;
654	
655		RTLIL::Memory *mem = canvas->memories.at(id(name));
656		log_assert(mem);
657	
658		uint64_t processed = 0;
659	
660		using RTLIL::Const;
661		using RTLIL::S0;
662		using RTLIL::S1;
663		using RTLIL::Sx;
664	
665		// Depending on the offset alignment with respect to word boundaries
666		// we might need to emit up to 3 instances of the `$meminit_v2` cell.
667		if (bit_offset % mem->width != 0) {
668			int offset_in_cell = bit_offset % mem->width;
669			uint64_t length = std::min(mem->width - offset_in_cell, data.size());
670			Const data1, mask1;
671			data1.append(Const(Sx, offset_in_cell));
672			data1.append(data.extract(0, length));
673			data1.append(Const(Sx, mem->width - offset_in_cell - length));
674			mask1.append(Const(S0, offset_in_cell));
675			mask1.append(Const(S1, length));
676			mask1.append(Const(S0, mem->width - offset_in_cell - length));
677			emit_meminit_cell(mem, bit_offset / mem->width, big_endian, data1, mask1);
678			processed += length;
679		}
680	
681		if (processed < (uint64_t)data.size()) {
682			log_assert((bit_offset + processed) % mem->width == 0);
683			uint64_t length = ((((uint64_t)data.size()) - processed) / mem->width) * mem->width;
684			emit_meminit_cell(mem, (bit_offset + processed) / mem->width, big_endian,
685					data.extract(processed, length), RTLIL::Const(S1, mem->width));
686			processed += length;
687		}
688	
689		if (processed < (uint64_t)data.size()) {
690			uint64_t length = (uint64_t)data.size() - processed;
691			log_assert(length < (uint64_t)mem->width);
692			Const data1, mask1;
693			data1.append(data.extract(0, length));
694			data1.append(Const(Sx, mem->width - length));
695			mask1.append(Const(S1, length));
696			mask1.append(Const(S0, mem->width - length));
697			emit_meminit_cell(mem, bit_offset / mem->width, big_endian, data1, mask1);
698			processed += length;
699		}
700	
701		log_assert(processed == (uint64_t)data.size());
702	}
703	
704	SigSpec RTLILBuilder::add_placeholder_signal(
705			uint64_t width, std::string_view name_suggestion, bool public_name)
706	{
707		log_assert(width <= (uint64_t)std::numeric_limits<int>::max());
708		RTLIL::IdString name;
709		if (public_name) {
710			name = id(name_suggestion);
711		} else {
712			name = new_id(std::string(name_suggestion));
713		}
714		RTLIL::Wire *wire = canvas->addWire(name, (int)width);
715		wire->attributes = staged_attributes;
716		return wire;
717	}
718	
719	}; // namespace slang_frontend
